        static constexpr uint32 NPC_HIGH_NETHERMANCER_ZEREVOR = 22950;
        static constexpr uint32 NPC_LADY_MALANDE = 22951;
        static constexpr uint32 NPC_VERAS_DARKSHADOW = 22952;

