void bot_ai::DamageDealt(Unit* victim, uint32& damage, DamageEffectType /*damageType*/, SpellSchoolMask /*damageSchoolMask*/)
{
    if (victim == me)
        return;

    if (damage)
    {
        if (Creature* cre = victim->ToCreature())
        {
            ReliquaryBot::ThrottleOutgoingDamage(me, this, cre, damage);
            IllidariCouncilBot::ThrottleOutgoingDamage(me, this, cre, damage);

            if (!cre->hasLootRecipient())
                cre->SetLootRecipient(master);

            //controlled case is handled in Unit::DealDamage
            if (IAmFree())
                cre->LowerPlayerDamageReq(std::min<uint32>(cre->GetHealth(), damage) / (BotMgr::IsWanderingWorldBot(me) ? 4 : 2));
        }
    }

    if (victim->IsPlayer())
        ResetChase(victim);
}
